using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();
        private GameObject _torchRoot;

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");
            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            LoadShopData();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                Debug.Log($"[ShopPanel] {itemData.name} 已达购买上限");
                return;
            }

            int price = itemData.discount > 0
                ? itemData.price * (100 - itemData.discount) / 100
                : itemData.price;

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[ShopPanel] PlayerWallet not found");
                return;
            }

            bool success = itemData.currencyType switch
            {
                CurrencyType.Gold => wallet.SpendGold(price),
                CurrencyType.Diamond => wallet.SpendDiamond(price),
                CurrencyType.Free => true,
                _ => false
            };

            if (!success)
            {
                string curName = itemData.currencyType switch
                {
                    CurrencyType.Gold => "金币不足",
                    CurrencyType.Diamond => "钻石不足",
                    _ => "无法购买"
                };
                Debug.Log($"[ShopPanel] 购买失败: {itemData.name} - {curName}");
                return;
            }

            Debug.Log($"[ShopPanel] 购买成功: {itemData.name}, 花费: {price}");

            itemData.purchasedCount++;
            RefreshItemList();
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 100;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;

        private LevelData _currentLevelData;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            base.Awake();
            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene")
            {
                LoadLevel(0);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;
            UnityEngine.SceneManagement.SceneManager.LoadScene(
                UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
            );
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.UI
{
    public class MovingClouds : MonoBehaviour
    {
        [Header("Cloud Settings")]
        [SerializeField] private int _cloudCount = 8;
        [SerializeField] private float _minSpeed = 25f;
        [SerializeField] private float _maxSpeed = 60f;
        [SerializeField] private float _minScale = 0.5f;
        [SerializeField] private float _maxScale = 1.6f;
        [SerializeField] private float _cloudAlpha = 0.55f;

        [Header("Spawn Range (UI coordinates)")]
        [SerializeField] private float _spawnY = 250f;
        [SerializeField] private float _yRandomRange = 350f;
        [SerializeField] private int _cloudSortOrder = -5;

        private RectTransform _canvasRect;
        private float _canvasWidth;
        private float _canvasHeight;

        private void Start()
        {
            Canvas canvas = GetComponentInParent<Canvas>();
            if (canvas != null)
            {
                _canvasRect = canvas.GetComponent<RectTransform>();
                _canvasWidth = _canvasRect.rect.width;
                _canvasHeight = _canvasRect.rect.height;
            }
            else
            {
                _canvasWidth = 1920f;
                _canvasHeight = 1080f;
            }

            for (int i = 0; i < _cloudCount; i++)
            {
                CreateCloud(randomX: true);
            }
        }

        private void CreateCloud(bool randomX = false)
        {
            GameObject cloudObj = new GameObject("Cloud");
            cloudObj.transform.SetParent(transform, false);

            RectTransform rt = cloudObj.AddComponent<RectTransform>();

            Canvas cloudCanvas = cloudObj.AddComponent<Canvas>();
            cloudCanvas.overrideSorting = true;
            cloudCanvas.sortingOrder = _cloudSortOrder;

            Image cloudImg = cloudObj.AddComponent<Image>();

            Texture2D tex = GenerateCloudTexture();
            Sprite sprite = Sprite.Create(tex, new Rect(0, 0, tex.width, tex.height), new Vector2(0.5f, 0.5f));
            cloudImg.sprite = sprite;
            cloudImg.color = new Color(1f, 1f, 1f, _cloudAlpha);
            cloudImg.raycastTarget = false;

            float scale = Random.Range(_minScale, _maxScale);
            rt.localScale = new Vector3(scale, scale, 1f);

            float startX = randomX ? Random.Range(-_canvasWidth / 2, _canvasWidth / 2) : _canvasWidth / 2 + 200f;
            float startY = _spawnY + Random.Range(-_yRandomRange, _yRandomRange);
            rt.anchoredPosition = new Vector2(startX, startY);

            CloudMover mover = cloudObj.AddComponent<CloudMover>();
            float speed = Random.Range(_minSpeed, _maxSpeed);
            mover.Initialize(speed, _canvasWidth, rt, this);
        }

        private Texture2D GenerateCloudTexture()
        {
            int w = 256;
            int h = 128;
            Texture2D tex = new Texture2D(w, h);
            Color[] pixels = new Color[w * h];

            for (int y = 0; y < h; y++)
            {
                for (int x = 0; x < w; x++)
                {
                    float nx = (float)x / w;
                    float ny = (float)y / h;

                    float d = Ellipse(nx, ny, 0.5f, 0.45f, 0.4f, 0.35f);
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.3f, 0.55f, 0.22f, 0.25f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.7f, 0.55f, 0.22f, 0.25f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.5f, 0.6f, 0.28f, 0.2f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.4f, 0.7f, 0.15f, 0.12f));
                    d = Mathf.Max(d, Ellipse(nx, ny, 0.6f, 0.7f, 0.15f, 0.12f));

                    float alpha = Mathf.SmoothStep(0f, 1f, d);
                    pixels[y * w + x] = new Color(1f, 1f, 1f, alpha);
                }
            }

            tex.SetPixels(pixels);
            tex.Apply();
            return tex;
        }

        private float Ellipse(float nx, float ny, float cx, float cy, float rx, float ry)
        {
            float dx = (nx - cx) / rx;
            float dy = (ny - cy) / ry;
            return 1f - (dx * dx + dy * dy);
        }

        internal void OnCloudExitedScreen(CloudMover mover)
        {
            CreateCloud(randomX: false);
            Destroy(mover.gameObject);
        }

        internal class CloudMover : MonoBehaviour
        {
            private float _speed;
            private float _canvasWidth;
            private RectTransform _rt;
            private MovingClouds _owner;

            public void Initialize(float speed, float canvasWidth, RectTransform rt, MovingClouds owner)
            {
                _speed = speed;
                _canvasWidth = canvasWidth;
                _rt = rt;
                _owner = owner;
            }

            private void Update()
            {
                if (_rt == null) return;

                Vector2 pos = _rt.anchoredPosition;
                pos.x -= _speed * Time.deltaTime;
                _rt.anchoredPosition = pos;

                if (pos.x < -_canvasWidth / 2 - 300f)
                {
                    _owner.OnCloudExitedScreen(this);
                }
            }
        }
    }
}

