var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
UnityEngine.Debug.Log($"Scene: {scene.name}");
var roots = scene.GetRootGameObjects();
foreach (var go in roots)
{
    PrintTree(go, 0);
}

void PrintTree(UnityEngine.GameObject go, int depth)
{
    string indent = new string(' ', depth * 2);
    string info = $"{indent}{go.name} (active:{go.activeSelf})";
    // Check for ParticleSystem
    var ps = go.GetComponent<UnityEngine.ParticleSystem>();
    if (ps != null) info += " [ParticleSystem]";
    var mc = go.GetComponent<TowerDefense.UI.MovingClouds>();
    if (mc != null) info += " [MovingClouds]";
    var sp = go.GetComponent<TowerDefense.UI.ShopPanel>();
    if (sp != null) info += " [ShopPanel]";
    UnityEngine.Debug.Log(info);
    foreach (UnityEngine.Transform child in go.transform)
    {
        PrintTree(child.gameObject, depth + 1);
    }
}

