        UnityEngine.Debug.Log($"  Grid cellSize: {tm.layoutGrid?.cellSize}");
        foreach (var pos in bounds.allPositionsWithin)
        {
            if (tm.GetTile(pos) != null)
            {
                var worldPos = tm.CellToWorld(pos);
                UnityEngine.Debug.Log($"  Sample tile cell {pos} -> world {worldPos}");
                break;
            }
        }
    }
}

