var cam = UnityEngine.Camera.main;
UnityEngine.Debug.Log($"Camera: pos={cam.transform.position}, orthoSize={cam.orthographicSize}");

var tilemaps = UnityEngine.Object.FindObjectsOfType<UnityEngine.Tilemaps.Tilemap>();
foreach (var tm in tilemaps)
{
    var bounds = tm.cellBounds;
    int tileCount = 0;
    foreach (var pos in bounds.allPositionsWithin)
    {
        if (tm.GetTile(pos) != null) tileCount++;
    }
    UnityEngine.Debug.Log($"Tilemap '{tm.name}': pos={tm.transform.position}, localPos={tm.transform.localPosition}, parent={tm.transform.parent?.name}, parentPos={tm.transform.parent?.position}");
    UnityEngine.Debug.Log($"  bounds={bounds}, tileCount={tileCount}, grid={tm.layoutGrid?.cellSize}");

    if (tileCount > 0)
    {
        foreach (var pos in bounds.allPositionsWithin)
        {
            if (tm.GetTile(pos) != null)
            {
                UnityEngine.Debug.Log($"  Sample cell {pos} -> world {tm.CellToWorld(pos)}");
                break;
            }
        }
    }
}

var cam = UnityEngine.Camera.main;
// What does the camera see?
float visH = cam.orthographicSize * 2; // 1088
float visW = visH * cam.aspect; // 1934
float minX = cam.transform.position.x - visW / 2; // 960 - 967 = -7
float maxX = cam.transform.position.x + visW / 2; // 960 + 967 = 1927
float minY = cam.transform.position.y - visH / 2; // 544 - 544 = 0
float maxY = cam.transform.position.y + visH / 2; // 544 + 544 = 1088

UnityEngine.Debug.Log($"Camera visible: X[{minX}, {maxX}] Y[{minY}, {maxY}]");
UnityEngine.Debug.Log($"Map extent: X[0, {30*64}] Y[0, {17*64}]");
UnityEngine.Debug.Log($"Near clip: {cam.nearClipPlane}, Far clip: {cam.farClipPlane}");

// Check the tilemap renderer
var groundTm = UnityEngine.GameObject.Find("Ground")?.GetComponent<UnityEngine.Tilemaps.Tilemap>();
if (groundTm != null)
{
    var rend = groundTm.GetComponent<UnityEngine.Tilemaps.TilemapRenderer>();
    UnityEngine.Debug.Log($"Ground renderer: enabled={rend.enabled}, sortingOrder={rend.sortingOrder}, layer={rend.gameObject.layer}");

    // Check if the tiles have valid sprites
    var tile = groundTm.GetTile<UnityEngine.Tilemaps.Tile>(new UnityEngine.Vector3Int(0, 0, 0));
    if (tile != null)
        UnityEngine.Debug.Log($"Sample tile: name={tile.name}, type={tile.GetType().Name}");
    else
        UnityEngine.Debug.Log($"Sample tile is NULL or not a Tile!");
}

// Check Canvas
var canvas = UnityEngine.Object.FindObjectOfType<UnityEngine.Canvas>();
if (canvas != null)
    UnityEngine.Debug.Log($"Canvas: renderMode={canvas.renderMode}, sortingOrder={canvas.sortingOrder}, planeDistance={canvas.planeDistance}");

