// Let's manually test if the tilemap is rendering by checking a world point
var cam = UnityEngine.Camera.main;

// Check what the camera actually renders - use a render texture approach
// Or simpler: check the tile sprite at a specific position
var groundTm = UnityEngine.GameObject.Find("Ground")?.GetComponent<UnityEngine.Tilemaps.Tilemap>();
if (groundTm != null)
{
    // Get the tile at center of camera view
    var centerWorld = new UnityEngine.Vector3(960, 544, 0);
    var centerCell = groundTm.WorldToCell(centerWorld);
    var tile = groundTm.GetTile(centerCell);
    UnityEngine.Debug.Log($"Cell at camera center (960,544): cell={centerCell}, tile={tile?.name ?? "null"}");

    // Check tile at (0,0)
    var tile00 = groundTm.GetTile(new UnityEngine.Vector3Int(0, 0, 0));
    UnityEngine.Debug.Log($"Cell (0,0) tile: {tile00?.name ?? "null"}, type={tile00?.GetType().Name ?? "null"}");

    // Check tile at (15, 8) - roughly center
    var tileCenter = groundTm.GetTile(new UnityEngine.Vector3Int(15, 8, 0));
    UnityEngine.Debug.Log($"Cell (15,8) tile: {tileCenter?.name ?? "null"}, type={tileCenter?.GetType().Name ?? "null"}");
}

// Check the AnimatedTile issue - do tiles have sprites?
var grassTile = groundTm?.GetTile(new UnityEngine.Vector3Int(0, 0, 0)) as UnityEngine.Tilemaps.AnimatedTile;
if (grassTile != null)
{
    UnityEngine.Debug.Log($"GrassTile is AnimatedTile, m_AnimatedSprites length={grassTile.m_AnimatedSprites?.Length ?? -1}");
    if (grassTile.m_AnimatedSprites != null && grassTile.m_AnimatedSprites.Length > 0)
    {
        var sprite = grassTile.m_AnimatedSprites[0];
        UnityEngine.Debug.Log($"  First sprite: {sprite?.name ?? "null"}, texture={sprite?.texture?.name ?? "null"}");
    }
}

