    foreach (var img in images)
    {
        if (img.rectTransform.rect.width > 500 && img.color.a > 0.3f)
            UnityEngine.Debug.Log($"Large Image: {GetPath(img.transform)}, size={img.rectTransform.rect.size}, color={img.color}, active={img.gameObject.activeInHierarchy}");
    }

    var sprites = go.GetComponentsInChildren<UnityEngine.SpriteRenderer>(true);
    foreach (var sr in sprites)
    {
        UnityEngine.Debug.Log($"Sprite: {GetPath(sr.transform)}, size={sr.bounds.size}, pos={sr.transform.position}, sortingOrder={sr.sortingOrder}, active={sr.gameObject.activeInHierarchy}");
    }
}

string GetPath(UnityEngine.Transform t)
{
    string path = t.name;
    while (t.parent != null) { t = t.parent; path = t.name + "/" + path; }
    return path;
}

